export const getRelocationRealities = (country) => {
    if (specificRealities[country.id]) return specificRealities[country.id];
    
    let regionKey = 'westernEurope'; 
    if (['norway','denmark','finland','iceland'].includes(country.id)) regionKey = 'nordic';
    else if (['spain','italy','greece','malta','cyprus','croatia'].includes(country.id)) regionKey = 'southernEurope';
    else if (['poland','czech-republic','hungary','romania','bulgaria','slovakia','estonia','latvia','lithuania','serbia','slovenia'].includes(country.id)) regionKey = 'easternEurope';
    else if (['singapore','south-korea','hong-kong','taiwan'].includes(country.id)) regionKey = 'asiaDeveloped';
    else if (['thailand','vietnam','malaysia','indonesia','philippines','india','sri-lanka','nepal','cambodia'].includes(country.id)) regionKey = 'asiaDeveloping';
    else if (['mexico','brazil','argentina','colombia','chile','peru','ecuador','costa-rica','panama','uruguay','paraguay','nicaragua','guatemala'].includes(country.id)) regionKey = 'americas';
    else if (['united-kingdom','ireland','united-states','canada','australia','new-zealand'].includes(country.id)) regionKey = 'englishSpeaking';
    
    return regionDefaults[regionKey];
};